def retrieve(question, k=4):
    q_vec = embedder.encode(question).tolist()
    res = collection.query(query_embeddings=[q_vec],
                           n_results=k)
    # zip text with its id so we can cite later
    return list(zip(res["ids"][0], res["documents"][0]))

hits = retrieve("How many vacation days do I get?")
for cid, txt in hits:
    print(cid, "->", txt[:60])

def answer_with_sources(question, k=4):
    hits = retrieve(question, k)
    text = answer(question, k)
    return {
        "answer": text,
        "sources": [cid for cid, _ in hits],
    }

result = answer_with_sources("Refund window?")
print(result["sources"])  # ['chunk-3', 'chunk-3', ...]

def recall_at_k(eval_set, k=4):
    hits = 0
    for q, gold_id in eval_set:
        ids = [cid for cid, _ in retrieve(q, k)]
        hits += gold_id in ids
    return hits / len(eval_set)

# eval_set = [("refund window?", "chunk-3"), ...]
print("recall@4:", recall_at_k(eval_set))
